import { IntentProps } from '../../../../core/slots/Intent/Intent.js';
import {
  BaseToolbarProps,
  InternalChartToolbarConfig,
} from '../../../core/types/toolbar.js';

/** Props for the ChartToolbar implementation in MeterBarChart
 * @public
 */
export type MeterBarToolbarSlotProps = BaseToolbarProps;

/**
 * Properties configurable by MeterBarConfiguration Provider
 * @public
 */
export type MeterBarToolbarConfig = MeterBarToolbarSlotProps & {
  intents?: Array<IntentProps>;
};

export interface MeterBarToolbarInternalProps
  extends InternalChartToolbarConfig {
  /** Decides if the toolbar is visible or hidden
   * @defaultValue false
   */
  hidden?: boolean;
  intents?: Array<IntentProps>;
}

export const defaultToolbarInternalConfig: MeterBarToolbarInternalProps = {
  hidden: false,
  intents: [],
  placement: 'top-right',
  collapsed: false,
  draggable: false,
};
